import React from 'react';
import PropTypes from 'prop-types';
import { ListGroup } from '@andes/list';
import groupNodeGenerator from '@andes/list/build/generators/groupNodeGenerator';
import { GROUP_DISPLAY_NAME } from '../constants/components';

/**
 * @type {typeof import('../../index').FloatingMenuGroup
 * & { getCollectionNode: (props: typeof import('../../index').FloatingMenuGroup) => Generator }}
 */
const FloatingMenuGroup = ({ children, ...props }) => (
  <ListGroup {...props}>
    {children}
  </ListGroup>
);

FloatingMenuGroup.getCollectionNode = groupNodeGenerator;

FloatingMenuGroup.displayName = GROUP_DISPLAY_NAME;

FloatingMenuGroup.propTypes = {
  children: PropTypes.oneOfType([PropTypes.element, PropTypes.arrayOf(PropTypes.element.isRequired)]).isRequired,
};

export default FloatingMenuGroup;
