import React from 'react';
import PropTypes from 'prop-types';
import { ListActionItem, ListItem } from '@andes/list';
import itemNodeGenerator from '@andes/list/build/generators/itemNodeGenerator';
import { ITEM_DISPLAY_NAME } from '../constants/components';

/** @typedef {import('../../index').FloatingMenuItemProps} FloatingMenuItemPublicProps */

/**
 * @typedef {Object} FloatingMenuItemInternalProps
 * @prop {number} [index]
 * @prop {number} [groupIndex]
 */

/** @typedef {FloatingMenuItemPublicProps & FloatingMenuItemInternalProps} FloatingMenuItemMergedProps */

/**
 * @type {React.FunctionComponent<FloatingMenuItemMergedProps>
 * & { getCollectionNode: (props: FloatingMenuItemMergedProps) => Generator }}
 */
const FloatingMenuItem = ({
  children,
  description,
  disabled = false,
  groupIndex,
  href,
  index,
  onClick,
  rightContent,
  selected = false,
  title,
  value,
  ...props
}) => {
  const itemProps = {
    description,
    disabled,
    groupIndex,
    index,
    rightContent,
    selected,
    title,
    value,
    ...props,
  };

  /** @type {(e: React.MouseEvent<HTMLAnchorElement | HTMLButtonElement>) => void} */
  const onClickHandler = e => {
    if (!disabled) {
      if (typeof onClick === 'function') {
        onClick(e, value);
      }
    }
  };

  if (href || onClick) {
    return (
      <ListActionItem
        {...itemProps}
        href={href}
        onClick={onClickHandler}
        // @ts-expect-error: internal props
        legacyBehaviorSlot
        chevron={false}
      >
        {children}
      </ListActionItem>
    );
  }

  return (
    <ListItem {...itemProps} onClick={onClickHandler}>
      {children}
    </ListItem>
  );
};

FloatingMenuItem.getCollectionNode = itemNodeGenerator;

FloatingMenuItem.displayName = ITEM_DISPLAY_NAME;

FloatingMenuItem.propTypes = {
  children: PropTypes.node,
  description: PropTypes.node,
  disabled: PropTypes.bool,
  groupIndex: PropTypes.number,
  href: PropTypes.string,
  index: PropTypes.number,
  onClick: PropTypes.func,
  rightContent: PropTypes.node,
  selected: PropTypes.bool,
  title: PropTypes.string,
  value: PropTypes.string.isRequired,
};

export default FloatingMenuItem;
