import React, { cloneElement, useRef, useEffect } from 'react';
import PropTypes from 'prop-types';
import classNames from 'classnames';
import { useAndesContext, useId } from '@andes/context';
import { useThemeContext } from '@andes/themes';
import { Popper } from '@andes/popper';
import { withTracker } from '@andes/with-tracker';
import { TAB, ARROW_DOWN, ARROW_UP, ENTER } from '@andes/common/build/constants/keyboardCodes';
import useFloatingMenu from '../hooks/useFloatingMenu';
import FloatingMenuSearch from './FloatingMenuSearch';
import FloatingMenuList from './FloatingMenuList';
import { namespace } from '../constants/common';
import { SEARCH_BOX_SIZE } from '../constants/layout';
import computeSearchProps from '../utils/computeSearchProps';
import { FloatingMenuMetrics } from '../metrics';
import enTranslations from '../../translations/en/messages.json';
import esArTranslations from '../../translations/es-AR/messages.json';
import ptBrTranslations from '../../translations/pt-BR/messages.json';
import zhCNTranslations from '../../translations/zh-CN/messages.json';

/**
 * @typedef {Object} FloatingMenuInternalProps
 * @prop {() => HTMLElement} [appendTo]
*/

/** @type {React.FunctionComponent<import('../../index').FloatingMenuProps & FloatingMenuInternalProps>} */
const FloatingMenu = ({ ref, ...props }) => {
  const {
    allowUnselect = false,
    appendTo,
    bottomContent,
    className,
    defaultOpen = false,
    id,
    menuMaxHeight,
    multiple = false,
    placement = 'bottom',
    search = false,
    srLabel,
    topContent,
    trigger,
    type = 'menu',
    width = 280,
    dialogSrLabel,
  } = props;

  const componentId = useId(id);
  const { getThemedComponentClasses, themeHash } = useThemeContext();

  // TODO: Analyze if we can find a better solution for this
  // Since popper renders the list conditionally, we need to register the list component on SSR
  getThemedComponentClasses?.('list');

  const searchConfig = computeSearchProps({ search });

  const { i18n } = useAndesContext(
    '@andes/floating-menu',
    { en: enTranslations, 'es-AR': esArTranslations, 'pt-BR': ptBrTranslations, 'zh-CN': zhCNTranslations },
  );

  const listId = `${componentId}-list`;

  const triggerRef = useRef(null);
  /** @type {React.RefObject<HTMLUListElement | null>} */
  const menuRef = useRef(null);
  const searchBoxRef = useRef(null);

  const hasSearched = useRef(false);

  const {
    menuProps,
    triggerProps,
  } = useFloatingMenu(
    triggerRef,
    menuRef,
    searchBoxRef,
    {
      ...props,
      allowUnselect,
      defaultOpen,
      multiple,
      placement,
      type,
      width,
      listId,
      id: componentId,
      searchConfig,
    },
  );

  const {
    closeMenu,
    getFocusedItem,
    onSearchChangeText,
    onSearchFocus,
    onSearchSelectionChange,
    onSelectionChange,
    options,
    selectedKeys,
    ...otherMenuProps
  } = menuProps;

  useEffect(() => {
    if (hasSearched.current) {
      hasSearched.current = false;
      if (typeof onSearchFocus === 'function') onSearchFocus();
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [hasSearched.current]);

  useEffect(() => {
    const menu = menuRef.current;
    if (menu && searchConfig) {
      requestAnimationFrame(() => {
        menu.style.maxHeight = menuMaxHeight ? `${menuMaxHeight - SEARCH_BOX_SIZE}px` : '';
        menu.style.overflowY = 'auto';
      });
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [menuRef.current, menuMaxHeight, searchConfig]);

  /**
   * @param {React.KeyboardEvent | React.MouseEvent} event
   * @param {string | string[]} [values]
   */
  const handleSelectionChange = (event, values) => {
    if (values) {
      onSelectionChange(event, values);
    } else if (typeof onSearchSelectionChange === 'function') {
      onSearchSelectionChange(event);
    }

    if (!multiple && typeof closeMenu === 'function') closeMenu();
  };

  /** @param {React.KeyboardEvent} event */
  const handleKeyDown = (event) => {
    // Simulates native select behaviour on type select
    switch (event.code) {
      case TAB:
        if (type !== 'menu') event.preventDefault();
        break;
      case ARROW_UP:
      case ARROW_DOWN:
        // @ts-expect-error: In a search environment, this is defined
        if (searchConfig) onSearchFocus(event);
        break;
      case ENTER:
        if (searchConfig) handleSelectionChange(event);
        break;
      default:
        break;
    }
  };

  /** @param {React.ChangeEvent<HTMLInputElement>} event */
  const handleSearchChange = (event) => {
    const { value } = event.target;

    hasSearched.current = true;
    if (typeof onSearchChangeText === 'function') onSearchChangeText(value);
    if (typeof searchConfig?.onChange === 'function') searchConfig.onChange(value);
  };

  const getContent = () => {
    const list = (
      <FloatingMenuList
        closeMenu={closeMenu}
        id={listId}
        multiple={multiple}
        onKeyDown={handleKeyDown}
        onSelect={handleSelectionChange}
        options={options}
        ref={menuRef}
        selectedKeys={selectedKeys}
        type={type}
        search={searchConfig?.search}
        srLabel={srLabel}
        visible={menuProps.visible}
        i18n={i18n}
        topContent={!searchConfig ? topContent : undefined}
        bottomContent={bottomContent}
        dialogSrLabel={dialogSrLabel}
      />
    );

    if (!searchConfig) return list;

    return (
      <FloatingMenuSearch
        getFocusedItem={getFocusedItem}
        handleKeyDown={handleKeyDown}
        list={list}
        listId={listId}
        ref={searchBoxRef}
        visible={menuProps.visible}
        id={componentId}
        {...searchConfig}
        onChange={handleSearchChange}
        dialogSrLabel={dialogSrLabel}
      />
    );
  };

  const containerClassNames = classNames(namespace, className, {
    [`${namespace}--multiple`]: multiple,
  });

  const contentClassName = classNames(`${namespace}__popper-content`, getThemedComponentClasses?.('floatingMenu'));

  return (
    <div
      className={containerClassNames}
      ref={ref}
    >
      <Popper
        appendTo={appendTo}
        content={getContent()}
        interactive
        placement={placement}
        id={`${componentId}-popper`}
        focusScope
        // @ts-expect-error: internal props
        classNames={{ content: contentClassName }}
        attrs={{
          root: themeHash,
          content: { 'data-andes-floating-menu': true, ...themeHash },
        }}
        {...otherMenuProps}
      >
        {
          cloneElement(/** @type {React.ReactElement} */ (trigger), {
            ref: triggerRef,
            ...triggerProps,
          })
        }
      </Popper>
    </div>
  );
};

FloatingMenu.displayName = 'FloatingMenu';

FloatingMenu.propTypes = {
  allowUnselect: PropTypes.bool,
  appendTo: PropTypes.func,
  bottomContent: PropTypes.node,
  children: PropTypes.oneOfType([
    PropTypes.element.isRequired,
    PropTypes.arrayOf(PropTypes.element.isRequired),
  ]).isRequired,
  className: PropTypes.string,
  defaultOpen: PropTypes.bool,
  defaultValue: PropTypes.oneOfType([
    PropTypes.string.isRequired,
    PropTypes.arrayOf(PropTypes.string.isRequired),
  ]),
  dialogSrLabel: PropTypes.string,
  id: PropTypes.string,
  menuMaxHeight: PropTypes.number,
  multiple: PropTypes.bool,
  onChange: PropTypes.func,
  onClose: PropTypes.func,
  onOpen: PropTypes.func,
  open: PropTypes.bool,
  placement: PropTypes.oneOf([
    'bottom',
    'bottom-start',
    'bottom-end',
    'top',
    'top-start',
    'top-end',
    'left',
    'left-start',
    'left-end',
    'right',
    'right-start',
    'right-end',
  ]),
  search: PropTypes.oneOfType([PropTypes.bool, PropTypes.shape({
    defaultValue: PropTypes.string,
    filterCondition: PropTypes.func,
    onChange: PropTypes.func,
    placeholder: PropTypes.string,
  })]),
  srLabel: PropTypes.string.isRequired,
  topContent: PropTypes.node,
  trigger: PropTypes.element.isRequired,
  type: PropTypes.oneOf(['menu', 'select']),
  value: PropTypes.oneOfType([
    PropTypes.string.isRequired,
    PropTypes.arrayOf(PropTypes.string.isRequired),
  ]),
  width: PropTypes.oneOfType([PropTypes.number, PropTypes.string]),
};

export { FloatingMenu };
export default withTracker(FloatingMenu, FloatingMenuMetrics);
