/* eslint-disable react-hooks/exhaustive-deps */
import React, { useEffect, useMemo, useState } from 'react';
import PropTypes from 'prop-types';
import classNames from 'classnames';

import { Checkbox } from '@andes/checkbox';
import { ListBox } from '@andes/listbox';
import { namespaceMenuMultiple } from '../constants/common';

/**
 * @typedef {Object} FloatingMenuMultipleProps
 * @prop {React.ReactElement | React.ReactElement[]} children
 * @prop {string} [className]
 * @prop {string[]} [defaultValue]
 * @prop {string} id
 * @prop {(
 * event: React.KeyboardEvent | React.MouseEvent,
 * values: string[],
 * itemDetails?: { value?: string
 * }) => void} [onSelect]
 * @prop {string} srLabel
 * @prop {string[]} [value]
 * @prop {React.RefObject<HTMLUListElement | null> | ((refElement: HTMLUListElement | null) => void)} [ref]
 */

/**
 * @typedef {Object} FloatingMenuMultipleInternalProps
 * @prop {boolean} [shouldUseVirtualFocus]
 */

/** @type {React.FunctionComponent<FloatingMenuMultipleProps & FloatingMenuMultipleInternalProps>} */
const FloatingMenuMultiple = ({
  children,
  className,
  defaultValue,
  onSelect,
  value,
  ref,
  ...listProps
}) => {
  const [currentValues, setCurrentValues] = useState(value || defaultValue);

  const isUncontrolled = useMemo(() => value === undefined, []);

  useEffect(() => {
    if (!isUncontrolled) {
      setCurrentValues(value);
    }
  }, [value]);

  /**
   * @param {React.KeyboardEvent | React.MouseEvent} event
   * @param {string[]} selectedValues
   * @param {{ value?: string }} itemDetails
   */
  const customOnSelect = (event, selectedValues, itemDetails) => {
    if (isUncontrolled) setCurrentValues(selectedValues);

    if (typeof onSelect === 'function') onSelect(event, selectedValues, itemDetails);
  };

  const getValuesArray = () => (Array.isArray(currentValues) ? currentValues : []);

  const stateProps = {};

  if (!isUncontrolled) {
    stateProps.selectedKeys = getValuesArray();
  } else if (defaultValue) {
    stateProps.defaultSelectedKeys = getValuesArray();
  }

  const floatingMenuMultipleClassNames = classNames(namespaceMenuMultiple, className);

  return (
    <ListBox
      className={floatingMenuMultipleClassNames}
      selectionComponent={<Checkbox srHidden />}
      selectionMode="multiple"
      ref={ref}
      onSelect={customOnSelect}
      {...listProps}
      {...stateProps}
    >
      {children}
    </ListBox>
  );
};

FloatingMenuMultiple.propTypes = {
  children: PropTypes.oneOfType([PropTypes.element, PropTypes.arrayOf(PropTypes.element.isRequired)]).isRequired,
  className: PropTypes.string,
  defaultValue: PropTypes.arrayOf(PropTypes.string.isRequired),
  id: PropTypes.string.isRequired,
  onSelect: PropTypes.func,
  value: PropTypes.arrayOf(PropTypes.string.isRequired),
};

FloatingMenuMultiple.displayName = 'FloatingMenuMultiple';

export default FloatingMenuMultiple;
