/**
 * @typedef {Object} ComputeSearchProps
 * @prop {import('../..').SearchConfigProps | boolean} search
 */

/** @param {ComputeSearchProps} computeSearchProps */
const computeSearchProps = ({ search: searchProps }) => {
  if (!searchProps) return undefined;

  if (typeof searchProps === 'boolean') {
    return { search: true };
  }

  return { ...searchProps, search: true };
};

export default computeSearchProps;
