import React from 'react';
import { FocusScope } from '@react-aria/focus';
import PropTypes from 'prop-types';
import warning from '@andes/common/build/utils/warning';
import { WARNING_DIALOG_SR_LABEL } from '../constants/warnings';
import { useAndesContext } from '@andes/context';
import { VisuallyHiddenFocusable } from '@andes/visually-hidden';
import { namespace } from '../constants/common';
import enTranslations from '../../translations/en/messages.json';
import esArTranslations from '../../translations/es-AR/messages.json';
import ptBrTranslations from '../../translations/pt-BR/messages.json';
import zhCNTranslations from '../../translations/zh-CN/messages.json';

/**
 * @typedef {Object} FloatingMenuListDialogContentProps
 * @prop {React.ReactNode} children
 * @prop {boolean} visible
 * @prop {string} id
 * @prop {string} [dialogSrLabel]
 * @prop {(() => void) | undefined} [closeMenu] - Function to close the menu
 */

/** @type {React.FunctionComponent<FloatingMenuListDialogContentProps>} */
// eslint-disable-next-line react/prop-types
const FloatingMenuListDialogContent = ({
  visible,
  children,
  id,
  dialogSrLabel,
  closeMenu,
}) => {
  warning(dialogSrLabel, WARNING_DIALOG_SR_LABEL);

  // Detect Android mobile to avoid issues with Talkback when focus is trapped
  const { device, i18n } = useAndesContext(
    '@andes/floating-menu',
    { en: enTranslations, 'es-AR': esArTranslations, 'pt-BR': ptBrTranslations, 'zh-CN': zhCNTranslations },
  );

  const shouldDisableFocusTrap = device?.osName === 'android' && device?.mobile;

  // Accessible close button as first element inside the focus trap for Android mobile
  const hiddenCloseButton = (
    <VisuallyHiddenFocusable
      onClick={closeMenu}
      type="button"
    >
      {i18n.pgettext(namespace, 'Cerrar menú')}
    </VisuallyHiddenFocusable>
  );

  return (
    <div
      role="dialog"
      aria-modal="true"
      aria-label={dialogSrLabel}
      id={`${id}-dialog`}
    >
      <FocusScope contain={!shouldDisableFocusTrap && visible} restoreFocus autoFocus>
        {shouldDisableFocusTrap && hiddenCloseButton}
        {children}
      </FocusScope>
    </div>
  );
};

FloatingMenuListDialogContent.propTypes = {
  children: PropTypes.node.isRequired,
  closeMenu: PropTypes.func,
  dialogSrLabel: PropTypes.string,
  id: PropTypes.string.isRequired,
  visible: PropTypes.bool.isRequired,
};

/**
 * @typedef {Object} FloatingMenuListSlottedProps
 * @prop {React.ReactNode} children
 * @prop {React.ReactNode} [topContent]
 * @prop {React.ReactNode} [bottomContent]
 * @prop {boolean} visible
 * @prop {boolean} [dialog]
 * @prop {string} id
 * @prop {string} [dialogSrLabel]
 * @prop {(() => void) | undefined} [closeMenu] - Function to close the menu
 */

/** @type {React.FunctionComponent<FloatingMenuListSlottedProps>} */
const FloatingMenuListSlotted = ({
  children,
  visible,
  topContent,
  bottomContent,
  dialog,
  dialogSrLabel,
  id,
  closeMenu,
}) => {
  const hasTopSlot = typeof topContent !== 'undefined';
  const hasBottomSlot = typeof bottomContent !== 'undefined';
  const isSlotted = hasTopSlot || hasBottomSlot;

  const content = (
    <>
      {topContent}
      {children}
      {bottomContent}
    </>
  );

  if (dialog === false) {
    return content;
  }

  if (dialog || isSlotted) {
    if (hasTopSlot) {
      // we need to render it conditionally so focusScope can focus the first element
      return (
        <>
          {visible && (
            <FloatingMenuListDialogContent
              visible={visible}
              id={id}
              dialogSrLabel={dialogSrLabel}
              closeMenu={closeMenu}
            >
              {content}
            </FloatingMenuListDialogContent>
          )}
        </>
      );
    }

    return (
      <FloatingMenuListDialogContent
        visible={visible}
        id={id}
        dialogSrLabel={dialogSrLabel}
        closeMenu={closeMenu}
      >
        {content}
      </FloatingMenuListDialogContent>
    );
  }

  return content;
};

export default FloatingMenuListSlotted;

FloatingMenuListSlotted.propTypes = {
  bottomContent: PropTypes.node,
  children: PropTypes.node.isRequired,
  closeMenu: PropTypes.func,
  dialog: PropTypes.bool,
  dialogSrLabel: PropTypes.string,
  id: PropTypes.string,
  topContent: PropTypes.node,
  visible: PropTypes.bool.isRequired,
};
