import React from 'react';
import PropTypes from 'prop-types';
import SearchBox from './SearchBox';
import { namespace } from '../constants/common';
import FloatingMenuListSlotted from './FloatingMenuSlotted';

/**
 * @typedef {Object} FloatingMenuSearchProps
 * @prop {import('../..').SearchConfigProps['defaultValue']} [defaultValue]
 * @prop {() => (string | undefined)} [getFocusedItem]
 * @prop {(event: React.KeyboardEvent) => void} [handleKeyDown]
 * @prop {React.ReactNode} list
 * @prop {string} listId
 * @prop {(event: React.ChangeEvent<HTMLInputElement>) => void} [onChange]
 * @prop {import('../..').SearchConfigProps['placeholder']} [placeholder]
 * @prop {boolean} visible
 * @prop {string} id
 * @prop {string} [dialogSrLabel]
 */

/**
 * @type {React.FunctionComponent<
 * FloatingMenuSearchProps & import('@andes/common').WithRef<HTMLDivElement>
 * >}
 */
const FloatingMenuSearch = ({
  defaultValue,
  getFocusedItem,
  handleKeyDown,
  list,
  listId,
  onChange,
  placeholder,
  visible,
  dialogSrLabel,
  id,
  ref,
}) => {
  const inputProps = {
    role: 'combobox',
    'aria-label': placeholder,
    'aria-autocomplete': 'list',
    'aria-controls': listId,
    // @ts-expect-error: In a search context, getFocusedItem will always be defined
    'aria-activedescendant': getFocusedItem() ? `${listId}-option-${getFocusedItem()}` : undefined,
    'aria-expanded': true,
  };

  return (
    <FloatingMenuListSlotted
      id={id}
      dialogSrLabel={dialogSrLabel}
      visible={visible}
      topContent={(
        <div className={`${namespace}__search-box`}>
          <SearchBox
            ref={ref}
            defaultValue={defaultValue}
            onChange={onChange}
            placeholder={placeholder}
            onKeyDown={handleKeyDown}
            // @ts-expect-error: JSDoc does not recognize 'list' as string in 'aria-autocomplete'
            inputProps={inputProps}
          />
        </div>
      )}
    >
      {list}
    </FloatingMenuListSlotted>
  );
};

FloatingMenuSearch.propTypes = {
  defaultValue: PropTypes.string,
  dialogSrLabel: PropTypes.string,
  getFocusedItem: PropTypes.func,
  handleKeyDown: PropTypes.func,
  id: PropTypes.string,
  list: PropTypes.node.isRequired,
  listId: PropTypes.string.isRequired,
  onChange: PropTypes.func,
  placeholder: PropTypes.string,
  visible: PropTypes.bool.isRequired,
};

FloatingMenuSearch.displayName = 'FloatingMenuSearch';

export default FloatingMenuSearch;
